const raw = $input.first().json.content.parts[0].text;

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (e) {
  throw new Error("Invalid JSON from Gemini");
}

return [{
  json: parsed
}];

const data = $input.first().json;

let message = `<b>📘 ${data.title}</b>\n\n`;
message += `<b>📌 Topic:</b> ${data.topic}\n\n`;

if (data.grammar_focus && data.grammar_focus.length) {
  message += `<b>🎯 Grammar Focus:</b>\n`;
  data.grammar_focus.forEach((item) => {
    message += `• ${item}\n`;
  });
  message += `\n`;
}

message += `<b>📝 Questions</b>\n`;

if (data.questions && data.questions.length) {
  data.questions.forEach((q) => {
    message += `\n<b>${q.number}. [${q.type}]</b>\n`;
    message += `${q.question}\n`;

    if (q.options && q.options.length) {
      q.options.forEach((opt, i) => {
        const label = String.fromCharCode(65 + i); // A, B, C, D
        message += `${label}. ${opt}\n`;
      });
    }

    if (q.instruction) {
      message += `<i>${q.instruction}</i>\n`;
    }
  });
} else {
  message += `No questions available.\n`;
}

return [
  {
    json: {
      telegram_message: message
    }
  }
];

const data = $input.first().json;

function esc(str = '') {
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

let message = `<b>✍️ ${esc(data.title || 'IELTS Writing Practice')}</b>\n\n`;

if (data.task_type) {
  message += `<b>🗂 Task Type:</b> ${esc(data.task_type)}\n\n`;
}

if (data.question) {
  const cleanQuestion = String(data.question).replace(/\n{3,}/g, '\n\n').trim();
  message += `<b>📌 Question</b>\n${esc(cleanQuestion)}\n\n`;
}

if (data.instructions) {
  message += `<b>📏 Instructions:</b> ${esc(data.instructions)}\n\n`;
}

if (data.tips && data.tips.length) {
  message += `<b>💡 Tips</b>\n`;
  data.tips.forEach((tip, index) => {
    message += `${index + 1}. ${esc(tip)}\n`;
  });
  message += `\n`;
}

message += `<b>📝 Your Task</b>\nWrite your answer and send it back to the bot for review.`;

return [
  {
    json: {
      telegram_message: message
    }
  }
];

const data = $input.first().json;

let message = `<b>📘 ${data.title}</b>\n\n`;
message += `<b>📌 Topic:</b> ${data.topic}\n\n`;

// Passage (dipotong biar tidak terlalu panjang)
message += `<b>📖 Passage</b>\n`;
message += `${data.passage.slice(0, 800)}...\n\n`;

message += `<b>📝 Questions</b>\n`;

data.questions.forEach(q => {
  message += `\n${q.number}. ${q.question}\n`;
});

return [{
  json: {
    telegram_message: message
  }
}];

const text = $input.first().json.telegram_message;
const chunkSize = 3500;

const chunks = [];

for (let i = 0; i < text.length; i += chunkSize) {
  chunks.push({
    json: {
      telegram_message: text.slice(i, i + chunkSize)
    }
  });
}

return chunks;

